Bash(node -e "
// Check more ingredient IDs for collisions
const mockIds = [
  ''chicken_breast'', ''chicken_thigh'', ''egg'', ''beef'', ''beef_brisket'',
  ''pork_loin'', ''pork_belly'', ''pork_ribs'', ''ground_pork'', ''lamb'',
  ''fish'', ''shrimp'', ''tofu'', ''broccoli'', ''tomato'',
  ''cucumber'', ''spinach'', ''mushroom'', ''bell_pepper'', ''seaweed'',
  ''cabbage'', ''radish'', ''eggplant'', ''chive'', ''cilantro'',
  ''wood_ear'', ''bean_sprout'', ''carrot'', ''potato'', ''enoki'',
  ''scallion'', ''ginger'', ''garlic'', ''sichuan_pepper'', ''bird_chili'',
  ''salt'', ''pepper'', ''soy_sauce'', ''vinegar'', ''chili'',
  ''sugar'', ''cooking_wine'', ''sesame_oil'', ''oyster_sauce'',
  ''milk'', ''yogurt'', ''cheese'',
  ''apple'', ''banana'', ''blueberry'',
  ''rice'', ''noodle'', ''oat''
];

// Also check recipeRef IDs (ingredient refs in recipes)
const recipeRefIds = [
  ''chicken_breast'', ''broccoli'', ''garlic'', ''salt'', ''pepper'',
  ''oat'', ''milk'', ''blueberry'', ''banana'', ''apple'', ''yogurt'',
  ''cucumber'', ''tomato'', ''cheese'',
  ''egg'', ''scallion'',
  ''pork_loin'', ''mushroom'', ''spinach'',
  ''seaweed'',
  ''pork_belly'', ''soy_sauce'',
  ''bell_pepper'', ''chili'', ''sichuan_pepper'', ''vinegar'',
  ''tofu'', ''ground_pork'',
  ''pork_ribs'', ''cooking_wine'', ''sugar'',
  ''radish'', ''ginger'',
  ''chicken_thigh'', ''oyster_sauce'',
  ''lamb'',
  ''beef_brisket'',
  ''eggplant'',
  ''bean_sprout'', ''bird_chili'',
  ''potato'',
  ''enoki'', ''carrot'',
  ''beef'', ''cilantro'', ''sesame_oil'',
  ''chive'',
  ''cabbage'',
  ''wood_ear'',
  ''fish'',
  ''shrimp''
];

const allIds = [...new Set([...mockIds, ...recipeRefIds])];

function foodIdFromIngredientId(id) {
  return [...id].reduce((sum, char) => sum + char.charCodeAt(0), 0);
}

const map = {};
for (const id of allIds) {
  const fid = foodIdFromIngredientId(id);
  if (!map[fid]) map[fid] = [];
  map[fid].push(id);
}

let duplicateCount = 0;
for (const [fid, ingredients] of Object.entries(map)) {
  if (ingredients.length > 1) {
    console.log(''DUPLICATE ID '' + fid + '': '' + ingredients.join('', ''));
    duplicateCount++;
  }
}

if (duplicateCount === 0) {
  console.log(''No duplicates found among all ingredient IDs'');
} else {
  console.log(''\nTotal '' + duplicateCount + '' duplicate ID groups found'');
}
")
